# Definition for singly-linked list.
class ListNode:
    def __init__(self, x):
        self.val = x
        self.next = None

class Solution:
    def detectCycle(self, head: ListNode) -> ListNode:
        if not head or not head.next:
            return None

        slow = head
        fast = head

        # Phase 1: Detect cycle and find meeting point
        # Using a while loop with an else clause for clarity if no cycle is found
        while fast and fast.next:
            slow = slow.next
            fast = fast.next.next
            if slow == fast:
                break
        else:
            # If the loop finished without a break, it means fast reached the end, so no cycle
            return None

        # Phase 2: Find the start of the cycle
        # Reset one pointer to the head and move both at the same pace
        # They will meet at the start of the cycle
        pointer1 = head
        pointer2 = slow # 'slow' is currently at the meeting point

        while pointer1 != pointer2:
            pointer1 = pointer1.next
            pointer2 = pointer2.next

        return pointer1 # Both pointers are now at the start of the cycle
